import{_ as a,o as t,c as r,ae as o}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Obscured Data","description":"","frontmatter":{"title":"Obscured Data","slug":"obscured-data"},"headers":[],"relativePath":"account-hub/obscured-data.md","filePath":"account-hub/obscured-data.md"}'),i={name:"account-hub/obscured-data.md"};function s(n,e,c,h,d,g){return t(),r("div",null,[...e[0]||(e[0]=[o('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Branch is committed to preserving user privacy, which means adhering to privacy-preserving mechanisms as well as the requirements established through our partnerships with third-parties.</p><p>If you&#39;ve been redirected here from a tooltip in Branch, this means data was obscured due to privacy practices that Branch has committed to.</p><p>Tooltip text: <code>&quot;We are unable to show this value due to data aggregation thresholds.&quot;</code></p><p>These practices are in the interest of respecting end users&#39; privacy and personal data.</p><h2 id="privacy-protocols" tabindex="-1">Privacy protocols <a class="header-anchor" href="#privacy-protocols" aria-label="Permalink to &quot;Privacy protocols&quot;">​</a></h2><p>Learn more about the privacy protocol the obfuscated data falls under using the descriptions below.</p><h3 id="predictive-aggregate-measurement" tabindex="-1">Predictive aggregate measurement <a class="header-anchor" href="#predictive-aggregate-measurement" aria-label="Permalink to &quot;Predictive aggregate measurement&quot;">​</a></h3><p><a href="./predictive-aggregate-measurement.html">Predictive Aggregate Measurement (PAM)</a> is a feature built by Branch that surfaces attribution data for marketers while implementing several <a href="./predictive-aggregate-measurement.html#data-precautions">data precautions</a> that bring user privacy to the forefront.</p><h3 id="facebook-aggregate-reporting" tabindex="-1">Facebook aggregate reporting <a class="header-anchor" href="#facebook-aggregate-reporting" aria-label="Permalink to &quot;Facebook aggregate reporting&quot;">​</a></h3><p><a href="./facebook-aggregate-reporting-changes.html">Facebook Aggregate Reporting</a> is the result of a partnership between Branch and Meta, where we&#39;ve aligned on obscuring user data in Facebook-attributed campaigns when aggregation levels are not high enough to maintain user privacy.</p>',11)])])}const l=a(i,[["render",s]]);export{u as __pageData,l as default};
